"""
    purchase_offering(offering_arn, reservation_name, start)
    purchase_offering(offering_arn, reservation_name, start, params::Dict{String,<:Any})

Submits a request to purchase an offering. If you already have an active reservation, you
can't purchase another offering.

# Arguments

- `offering_arn`: The Amazon Resource Name (ARN) of the offering.

- `reservation_name`: The name that you want to use for the reservation.

- `start`: The date and time that you want the reservation to begin, in Coordinated
  Universal Time (UTC).

  You can specify any date and time between 12:00am on the first day of the current month to
  the current time on today's date, inclusive. Specify the start in a 24-hour notation. Use
  the following format: `YYYY-MM-DDTHH:mm:SSZ`, where `T` and `Z` are literal characters.
  For example, to specify 11:30pm on March 5, 2020, enter `2020-03-05T23:30:00Z`.
"""
function purchase_offering end

function purchase_offering(
    OfferingArn, ReservationName, Start; aws_config::AbstractAWSConfig=current_aws_config()
)
    return mediaconnect(
        "POST",
        "/v1/offerings/$(OfferingArn)",
        Dict{String,Any}("ReservationName" => ReservationName, "Start" => Start);
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

function purchase_offering(
    OfferingArn,
    ReservationName,
    Start,
    params::AbstractDict{String};
    aws_config::AbstractAWSConfig=current_aws_config(),
)
    return mediaconnect(
        "POST",
        "/v1/offerings/$(OfferingArn)",
        Dict{String,Any}(
            mergewith(
                _merge,
                Dict{String,Any}("ReservationName" => ReservationName, "Start" => Start),
                params,
            ),
        );
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

